import React, { useState, useEffect } from "react";
import axios from "axios";
import "./SellerDashboard.css";

const API_BASE = "http://localhost:5000/api/products";

function SellerDashboard() {
  const [activePage, setActivePage] = useState("list");
  const [products, setProducts] = useState([]);
  const [form, setForm] = useState({
    name: "",
    description: "",
    category: "Earphone",
    price: "",
    offerPrice: "",
    image: "",
  });

  // Fetch products on mount
  useEffect(() => {
    fetchProducts();
  }, []);

  const fetchProducts = async () => {
    try {
      const res = await axios.get(API_BASE);
      setProducts(res.data);
    } catch (err) {
      console.error("Fetch products error:", err);
      alert("❌ Failed to load products");
    }
  };

  // Input change handler
  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  // Add new product
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post(API_BASE, form);
      setProducts([res.data, ...products]);
      setForm({
        name: "",
        description: "",
        category: "Earphone",
        price: "",
        offerPrice: "",
        image: "",
      });
      setActivePage("list");
    } catch (err) {
      console.error("Add product error:", err);
      alert("❌ Failed to add product");
    }
  };

  // Delete handler
  const handleDelete = async (id) => {
    if (!window.confirm("Delete this product?")) return;
    try {
      await axios.delete('${API_BASE}/${id}');
      setProducts(products.filter((p) => p._id !== id));
    } catch (err) {
      console.error("Delete error:", err);
      alert("❌ Failed to delete");
    }
  };

  return (
    <div className="seller-dashboard">
      {/* Sidebar */}
      <aside className="sidebar">
        <h1 className="logo">⚡ Seller Panel</h1>
        <ul>
          <li
            className={activePage === "add" ? "active" : ""}
            onClick={() => setActivePage("add")}
          >
            ➕ Add Product
          </li>
          <li
            className={activePage === "list" ? "active" : ""}
            onClick={() => setActivePage("list")}
          >
            📦 Product List
          </li>
          <li
            className={activePage === "orders" ? "active" : ""}
            onClick={() => setActivePage("orders")}
          >
            📝 Orders
          </li>
        </ul>
      </aside>

      {/* Main content */}
      <main className="main-content">
        {/* Add product page */}
        {activePage === "add" && (
          <form className="product-form" onSubmit={handleSubmit}>
            <h3>Add New Product</h3>
            <input
              type="text"
              name="name"
              value={form.name}
              onChange={handleChange}
              placeholder="Product Name"
              required
            />
            <textarea
              name="description"
              value={form.description}
              onChange={handleChange}
              placeholder="Product Description"
              rows="3"
            />
            <select
              name="category"
              value={form.category}
              onChange={handleChange}
            >
              <option>Earphone</option>
              <option>Mobile</option>
              <option>Laptop</option>
              <option>Accessory</option>
            </select>
            <input
              type="number"
              name="price"
              value={form.price}
              onChange={handleChange}
              placeholder="Price"
              required
            />
            <input
              type="number"
              name="offerPrice"
              value={form.offerPrice}
              onChange={handleChange}
              placeholder="Offer Price"
            />
            <input
              type="text"
              name="image"
              value={form.image}
              onChange={handleChange}
              placeholder="Image URL"
            />
            {form.image && <img src={form.image} alt="Preview" />}
            <div className="form-actions">
              <button type="submit">Add Product</button>
              <button type="button" onClick={() => setForm({})}>
                Reset
              </button>
            </div>
          </form>
        )}

        {/* Product list page */}
        {activePage === "list" && (
          <div>
            <h3>Product List</h3>
            <div className="product-list">
              {products.length === 0 ? (
                <p>No products yet</p>
              ) : (
                products.map((p) => (
                  <div key={p._id} className="product-item">
                    {p.image && <img src={p.image} alt={p.name} />}
                    <h4>{p.name}</h4>
                    <p>{p.description}</p>
                    <p>₹{p.price}</p>
                    {p.offerPrice && <small>Offer: ₹{p.offerPrice}</small>}
                    <div className="actions">
                      <button>Edit</button>
                      <button onClick={() => handleDelete(p._id)}>Delete</button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}

        {/* Orders page */}
        {activePage === "orders" && (
          <div>
            <h3>Orders</h3>
            <p>No orders yet.</p>
          </div>
        )}
      </main>
    </div>
  );
}

export default SellerDashboard;
